#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    bool sorted = true;
    for(int i = 0; i < n-1; i++) if(nums[i] > nums[i+1]) sorted = false;
    cout << (sorted ? "YES" : "NO");
}
